const b = $input.item.json.body || $input.item.json;
const title = b.title;
const lead = b.lead;
const body = b.body;
const pillar = b.pillar;
const draft_id = b.draft_id;
if (!title || !body || !pillar || !draft_id) throw new Error('Campos obrigatórios: draft_id, title, body, pillar');
const SYSTEM = 'Você é um editor médico que recebe prosa livre revisada por médico e reorganiza em JSON estruturado BlogPost para blog SEO. Preserve INTEGRALMENTE o conteúdo médico — não invente, não remova fatos. Apenas detecte estrutura (H2/H3/listas/destaques) e gere metadados (slug, meta, keywords, FAQs, excerpt). FAQs: 4-6 perguntas extraídas ou inferidas do corpo. Emita o resultado chamando a ferramenta emit_post com o objeto BlogPost estruturado.';
const USER = 'Reorganize este post para o blog da Clínica Okazaki (pilar: ' + pillar + ').

TÍTULO REVISADO:
' + title + '

LEAD REVISADO:
' + lead + '

CORPO REVISADO (markdown simples):
' + body + '

Gere JSON com shape exato: { slug (kebab-case derivado do título), pillar: "' + pillar + '", title: <título acima>, description (140-160 chars com geo-modifier em Recife), keywords (string CSV de 5-8 termos), h1: <título acima>, lead: <lead acima>, eyebrow: "BLOG · ' + pillar.toUpperCase() + '", breadcrumbLabel (curto), about (procedimento/condição), excerpt (80-200 chars), sections (array {id slug-style, h2, blocks: [{type, ...}]}), faqs (array {q, a} 4-6 itens extraídos do corpo), author: {name: "Dra. Jane Erika Frazão Okazaki", crm: "CRM-PE 19872", rqe: "RQE 17633", photo: "/assets/team/jane.webp", bio: "Médica geriatra do Centro Clínico Okazaki, responsável pela revisão clínica do conteúdo deste blog."}, publishedAt: ISO atual, updatedAt: ISO atual }. Block types disponíveis: p (parágrafo), h3 (sub-subtítulo), ul (lista de itens string[]), callout (destaque informativo), warning (alerta), inline-cta (CTA WhatsApp text + label), link (href + label). Inclua ao menos 1 link interno para /' + pillar + '. PRESERVE O CONTEÚDO MÉDICO LITERAL — apenas reorganize.';
return { json: { draft_id, system: SYSTEM, user: USER } };

const draft_id = $('Montar Prompt Reestruturação').item.json.draft_id;
const raw = $input.item.json;
const tu = (raw.content || []).find(c => c.type === 'tool_use');
if (!tu || !tu.input) throw new Error('Sem tool_use block. stop_reason=' + (raw.stop_reason || '?'));
const parsed = tu.input;
const req = ['slug','pillar','title','description','keywords','h1','lead','eyebrow','breadcrumbLabel','about','excerpt','sections','faqs','author'];
const miss = req.filter(k => !(k in parsed));
if (miss.length) throw new Error('Faltam: ' + miss.join(','));
if (!parsed.publishedAt) parsed.publishedAt = new Date().toISOString();
parsed.updatedAt = new Date().toISOString();
const kw = typeof parsed.keywords === 'string' ? parsed.keywords.split(',').map(k => k.trim()) : parsed.keywords;
const wc = JSON.stringify(parsed).split(/\s+/).length;
return { json: { draft_id, slug: parsed.slug, title: parsed.title, meta_description: parsed.description, keywords: kw, content_json: parsed, word_count: wc } };
